  if (espcontrol_language_code() == "it") return espcontrol_i18n_key_it(key);
  if (espcontrol_language_code() == "nb") return espcontrol_i18n_key_nb(key);
  if (espcontrol_language_code() == "nl") return espcontrol_i18n_key_nl(key);
  if (espcontrol_language_code() == "pl") return espcontrol_i18n_key_pl(key);
  if (espcontrol_language_code() == "pt-br") return espcontrol_i18n_key_pt_br(key);
  if (espcontrol_language_code() == "pt") return espcontrol_i18n_key_pt(key);
  if (espcontrol_language_code() == "ro") return espcontrol_i18n_key_ro(key);
  if (espcontrol_language_code() == "sk") return espcontrol_i18n_key_sk(key);
